# Pattern 1: Prompt Chaining — Code Examples

**Traditional Approach**

```typescript
// Traditional Monolithic Logic
function processUserRequest(request: string): string {
  // One giant function trying to do everything
  // High complexity, hard to debug, prone to spaghetti code
  const data = extractEntities(request);
  const sentiment = analyseSentiment(data);
  const summary = summariseText(data);
  const response = formulateResponse(summary, sentiment);
  return response;
}
```

**Agentic Approach**

```typescript
// Agentic Architecture — typed prompt chain
class PromptChain {
  async execute(userQuery: string): Promise<string> {
    // Step 1: Extraction Agent (The "Filter")
    // Objective: Clean and structure the raw input
    const context = await llm.invoke({
      prompt: "Extract entities and intent...",
      input: userQuery,
    });

    // Validation Gate (Traditional Code)
    if (!this.validateStructure(context)) {
      throw new Error("Step 1 failed extraction");
    }

    // Step 2: Analysis Agent (The "Processor")
    // Objective: Perform the core reasoning task
    const analysis = await llm.invoke({
      prompt: "Analyse sentiment and key themes...",
      input: context,
    });

    // Step 3: Synthesis Agent (The "Formatter")
    // Objective: Draft the final human-readable response
    const finalResponse = await llm.invoke({
      prompt: "Draft reply based on analysis...",
      input: analysis,
    });
    return finalResponse;
  }
}
```

# Pattern 2: Routing — Code Examples

**Traditional Approach**

```typescript
// Traditional Rule-based routing
function route(request: Request): Response {
  if (request.path.startsWith("/billing")) {
    return billingService.handle(request);
  } else if (request.path.startsWith("/support")) {
    return supportService.handle(request);
  } else {
    return defaultService.handle(request);
  }
}
```

**Agentic Approach**

```typescript
// Agentic Routing
async function routeRequest(userQuery: string): Promise<string> {
  // The Router is an Agent (or a classifier) itself
  // It decides the 'Strategy' at runtime
  const intent = await classificationAgent.invoke({
    prompt: "Classify intent: BILLING, SUPPORT, or GENERAL?",
    input: userQuery,
  });

  switch (intent) {
    case "BILLING":
      // Route to a model fine-tuned for financial data
      return billingAgent.run(userQuery);
    case "SUPPORT":
      // Route to a RAG-equipped agent with technical docs
      return supportAgent.run(userQuery);
    default:
      // Route to a general-purpose frontier model
      return generalAgent.run(userQuery);
  }
}
```

# Pattern 3: Parallelisation — Code Examples

**Traditional Approach**

```typescript
// Traditional: Blocking, sequential calls
function generateReport(topic: string): Report {
  const research = doResearch(topic);   // Takes 10s
  const outlines = draftOutlines(topic); // Takes 10s
  // Total time: 20s
  return combine(research, outlines);
}
```

**Agentic Approach**

```typescript
// Agentic Parallelisation — Async Scatter-Gather
async function agenticParallelFlow(query: string): Promise<string> {
  // Scatter: Launch 3 agents simultaneously
  const [research, legal, market] = await Promise.all([
    researchAgent.run(query),
    legalAgent.run(query),
    marketAgent.run(query),
  ]);

  // Gather: Use a Synthesis Agent to merge perspectives (Reduce phase)
  // The 'Reducer' is intelligent, not just a concatenator
  const finalReport = await synthesisAgent.invoke({
    prompt: "Synthesise these three perspectives into one report...",
    input: { research, legal, market },
  });
  return finalReport;
}
```

# Pattern 4: Reflection — Code Examples

**Traditional Approach**

```typescript
// Traditional: Single Pass Generation
function generateCode(spec: string): string {
  return codegenModule.generate(spec);
  // If it's buggy, the user finds out later in production.
}
```

**Agentic Approach**

```typescript
// Agentic Reflective Loop Architecture
async function generateRobustCode(spec: string): Promise<string> {
  // Draft Phase
  let code = await coderAgent.run(spec);

  // Reflection Loop (The "Code Review")
  for (let i = 0; i < MAX_RETRIES; i++) {
    // The Critic Agent acts as the Unit Test Suite
    const critique = await reviewerAgent.run(code);

    if (critique.isApproved) {
      return code;
    }
    // Feedback injection: The loop enables self-correction
    code = await coderAgent.run(spec, { feedback: critique.comments });
  }

  throw new Error("Max retries exceeded: unable to generate valid code");
}
```

# Pattern 5: Tool Use — Code Examples

**Traditional Approach**

```typescript
// Traditional hardcoded integration
function getWeather(city: string): WeatherData {
  // Developer decides this is always called here
  const data = fetch(\`api.weather.com/\${city}\`);
  return parse(data);
}

function main() {
  console.log(getWeather("Tokyo"));
}
```

**Agentic Approach**

```typescript
// Agentic Tool Use: Tool Definition (The "Adapter")
const weatherTool: Tool = {
  name: "get_weather",
  description: "Get current weather for a city. Input should be a city name.",
  func: callWeatherApi,
};

// The Agent decides IF/WHEN to call it
const agent = initializeAgent({ tools: [weatherTool], llm });

// The user prompt triggers the tool usage implicitly
const result = await agent.run("What should I wear in Tokyo today?");
// Internal Logic:
// 1. Thought: "I need to know the weather in Tokyo."
// 2. Action: Call tool 'get_weather' with arg 'Tokyo'
// 3. Observation: "It is 15°C and raining."
// 4. Final Answer: "Wear a raincoat."
```

# Pattern 6: Planning — Code Examples

**Traditional Approach**

```typescript
// Traditional Static Workflow
function handleReturnOrder(): void {
  // Hardcoded sequence
  validatePayment();
  checkInventory();
  shipReplacement();
  emailUser();
}
```

**Agentic Approach**

```typescript
// Dynamic Planning
// The Planner Agent generates the DAG at runtime
const plan = await plannerAgent.generatePlan({
  goal: "Handle a return for a damaged item",
});

// Generated Plan (Dynamic):
// 1. Ask user for photo of damage (Reasoning: Policy requires proof)
// 2. Verify purchase history
// 3. Generate shipping label
// 4. Refund wallet

for (const step of plan) {
  await executorAgent.execute(step);
  // Agent updates plan if a step fails (e.g., photo invalid)
}
```

# Pattern 7: Multi-Agent Collaboration — Code Examples

**Traditional Approach**

```typescript
// Monolith Class
class ContentGenerator {
  research() { /* ... */ }
  write() { /* ... */ }
  edit() { /* ... */ }
  run() {
    this.research();
    this.write();
    this.edit();
  }
}
```

**Agentic Approach**

```typescript
// Multi-Agent System
const researcher = new Agent({ role: "Researcher", goal: "Find facts", tools: [...] });
const writer = new Agent({ role: "Writer", goal: "Draft content", tools: [...] });

// Defining the collaboration workflow (The "Orchestrator")
const workflow = new Workflow();
workflow.addNode(researcher);
workflow.addNode(writer);

// Define the Handoff (The "Network Call")
workflow.addEdge(researcher, writer);
await workflow.run("Write a blog post about Agentic AI");
```

# Pattern 8: Memory Management — Code Examples

**Traditional Approach**

```typescript
// Traditional Session: Explicit State Persistence
// Developer manually manages what to store and retrieve
const userSession = db.getUserSession(userId);
const lastAction = userSession.lastAction;
const preferences = userSession.preferences;

// State is key-value: you ask for exactly what you stored
db.updateSession(userId, { lastAction: "viewed_pricing" });
```

**Agentic Approach**

```typescript
// Semantic Memory
// Instead of fetching by exact key, search by meaning
const relevantMemories = await vectorDb.similaritySearch(
  currentUserInput // "What pricing did we discuss?"
);
// Returns memories that are semantically related, even if
// the exact words differ from what was originally stored

// Inject retrieved memories into the prompt context
await agent.run({
  input: currentUserInput,
  context: relevantMemories, // Agent now "remembers" past interactions
});
```

# Pattern 9: Learning & Adaptation — Code Examples

**Traditional Approach**

```typescript
// Static code deployment: logic is frozen until next release
function calculateScore(x: number): number {
  return x * 1.5; // To change to 1.6, must redeploy the entire service
}
```

**Agentic Approach**

```typescript
// Adaptive Agent: updates its own behaviour based on feedback
if (userFeedback === "Bad response") {
  // Store this interaction as a negative example for future reference
  await memory.addNegativeExample(lastInteraction);

  // Modify the agent's own instructions — no redeployment needed
  await optimiser.updatePromptInstructions("Avoid using passive voice.");
  // Next time the agent runs, it will use the updated instructions
}
```

# Pattern 10: State Management (MCP) — Code Examples

**Traditional Approach**

```typescript
// Custom integration for every tool — Custom Glue Code
function connectToGithub() {
  // specific github logic...
}

function connectToSlack() {
  // specific slack logic...
}
```

**Agentic Approach**

```typescript
// MCP Client connects to generic MCP Servers — MCP Standard
// The client is agnostic to what the server actually is
await client.connect({ server: "github-mcp-server" });
await client.connect({ server: "slack-mcp-server" });

// Tools are auto-discovered and injected into the agent context
const tools = await client.listTools();
agent.bind(tools);
```

# Pattern 11: Goal Setting & Monitoring — Code Examples

**Traditional Approach**

```typescript
// Traditional Health Check: binary pass/fail on system metrics
function checkHealth(): void {
  const cpu = getCpuUsage();
  const latency = getAvgLatency();
  const errorRate = getErrorRate();

  if (cpu > 90 || latency > 500 || errorRate > 0.05) {
    alert("System unhealthy");
    restartService();
  }
}
```

**Agentic Approach**

```typescript
// Goal Monitoring Agent: Semantic Health Check
const currentState = agent.getState();
const goal = "Draft a complete report on Q3 earnings";

// The Monitor is an Agent
const status = await criticAgent.evaluate({
  criteria: "Is the report complete and accurate?",
  context: currentState,
});

if (status === "INCOMPLETE") {
  agent.plan.update("Gather more financial data");
  await agent.resume();
}
```

# Pattern 12: Exception Handling & Recovery — Code Examples

**Traditional Approach**

```typescript
// Deterministic Error Handling
try {
  await api.call();
} catch (e) {
  if (e instanceof TimeoutError) {
    await sleep(2000);
    await api.call(); // Retry exact same logic
  }
}
```

**Agentic Approach**

```typescript
// Agentic Recovery
const response = await tool.call();
if ("error" in response) {
  // Agent reflects on error and pivots strategy
  const planB = await agent.think(
    "Tool A failed with error. This path is blocked. " +
    "I should try searching Wikipedia instead to get the data."
  );
  await planB.execute();
}
```

# Pattern 13: Human-in-the-Loop — Code Examples

**Traditional Approach**

```yaml
# CI/CD Approval Gate
# Static Approval Step (YAML pipeline)
# steps:
#   - name: Wait for approval
#     uses: manual-approval-action
#     # Blocks until button click
```

**Agentic Approach**

```typescript
// Agentic Human-in-the-Loop
// The Agent proactively asks
if (action.riskLevel > threshold) {
  // 'humanTool' pauses execution and sends a msg to Slack/UI
  const userDecision = await humanTool.ask(
    "I am about to delete a production database. Proceed?"
  );
  if (userDecision === "Y") {
    await execute();
  } else {
    await agent.think("User rejected. Aborting task.");
  }
}
```

# Pattern 14: Knowledge Retrieval (RAG) — Code Examples

**Traditional Approach**

```sql
-- SQL Query
SELECT answer FROM faq WHERE topic = 'pricing';
```

**Agentic Approach**

```typescript
// Agentic RAG
// Semantic Retrieval
const docs = await retriever.getRelevantDocuments(
